import type { Theme } from '../theme';
/** CSS custom properties derived from the theme, set on the editor root. */
export declare function themeVars(theme: Theme): React.CSSProperties;
/** Scoped editor styles using data-tag attribute selectors. */
export declare const editorCSS = "\n  [data-hs-editor] {\n    color: var(--hs-text);\n    font-family: inherit;\n    font-weight: normal;\n    font-size: 1rem;\n    line-height: 1.6;\n    outline: none;\n    white-space: pre-wrap;\n    word-wrap: break-word;\n    min-height: 120px;\n    padding: 0.75rem;\n  }\n  [data-hs-editor]:empty::before {\n    content: attr(data-placeholder);\n    color: var(--hs-border);\n    pointer-events: none;\n    font-weight: normal;\n  }\n  [data-hs-editor] [data-tag=\"t\"] {\n    font-size: 2rem;\n    font-weight: bold;\n    color: var(--hs-light);\n    display: block;\n    line-height: 1.2;\n    margin-bottom: 0.25em;\n  }\n  [data-hs-editor] [data-tag=\"h\"],\n  [data-hs-editor] [data-tag=\"h2\"] {\n    font-size: 1.45rem;\n    font-weight: bold;\n    color: var(--hs-highlight);\n    display: block;\n    line-height: 1.3;\n    margin-bottom: 0.2em;\n  }\n  [data-hs-editor] [data-tag=\"h1\"] {\n    font-size: 1.75rem;\n    font-weight: bold;\n    color: var(--hs-highlight);\n    display: block;\n    line-height: 1.2;\n    margin-bottom: 0.2em;\n  }\n  [data-hs-editor] [data-tag=\"h3\"] {\n    font-size: 1.17rem;\n    font-weight: bold;\n    color: var(--hs-highlight);\n    display: block;\n    line-height: 1.3;\n    margin-bottom: 0.2em;\n  }\n  [data-hs-editor] [data-tag=\"b\"] {\n    font-weight: bold;\n    color: inherit;\n  }\n  [data-hs-editor] [data-tag=\"i\"] {\n    font-style: italic;\n    color: inherit;\n  }\n  [data-hs-editor] [data-tag=\"u\"] {\n    text-decoration: underline;\n    color: inherit;\n  }\n  [data-hs-editor] [data-tag=\"s\"] {\n    text-decoration: line-through;\n    color: inherit;\n  }\n  [data-hs-editor] [data-tag=\"hl\"] {\n    background-color: #dae197;\n    color: #2f3025;\n    font-weight: bold;\n    padding: 1px 4px;\n    border-radius: 4px;\n  }\n  [data-hs-editor] [data-tag=\"q\"] {\n    display: block;\n    font-style: italic;\n    margin-left: 20px;\n    border-left: 4px solid var(--hs-border);\n    color: var(--hs-highlight);\n    padding-left: 10px;\n    margin-top: 0.25em;\n    margin-bottom: 0.25em;\n  }\n  [data-hs-editor] [data-tag=\"code\"] {\n    display: block;\n    font-family: 'Fira Code', 'Courier New', monospace;\n    background: #2d2d2d;\n    color: #f8f8f2;\n    padding: 0.75rem 1rem;\n    border-radius: 6px;\n    font-size: 0.9em;\n    font-weight: normal;\n    white-space: pre;\n    overflow-x: auto;\n    margin: 0.5em 0;\n  }\n  [data-hs-editor] [data-tag=\"pre\"] {\n    display: block;\n    font-family: 'Fira Code', 'Courier New', monospace;\n    background: var(--hs-shade);\n    padding: 0.5em 0.75em;\n    border-radius: 4px;\n    font-size: 0.9em;\n    font-weight: normal;\n  }\n";
